import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import CurriculumPortal from './CurriculumPortal';


export default function App() {
  return (
    <Router basename="/staff-portal">
      <Routes>
        {/* Main Curriculum Page */}
        <Route path="/" element={<CurriculumPortal />} />
        
        {/* Deep Link for Curriculum (Optional but ready) */}
        <Route path="/curriculum/:className/:term/:week" element={<CurriculumPortal />} />
        
        </Routes>
    </Router>
  );
}